using NewSmartAIFactory.CompanyApi.Models;using NewSmartAIFactory.CompanyApi.Services;using Npgsql;using System.Text.Json;
namespace NewSmartAIFactory.CompanyApi.Endpoints;
public static class ApprovalEndpoints{public static IEndpointRouteBuilder MapApprovalEndpoints(this IEndpointRouteBuilder app){var g=app.MapGroup("/api/approvals").WithTags("Approvals");g.MapGet("/",async(string? status,ApprovalWorkflowService s,CancellationToken t)=>Results.Ok(await s.ListAsync(status,t)));g.MapGet("/{id}",async(string id,ApprovalWorkflowService s,CancellationToken t)=>{var item=await s.GetAsync(id,t);return item is null?Results.NotFound():Results.Ok(item);});g.MapPost("/",async(CreateApprovalRequest r,ApprovalWorkflowService s,EventStoreService events,CancellationToken t)=>{if(string.IsNullOrWhiteSpace(r.ProjectId)||string.IsNullOrWhiteSpace(r.Title)||string.IsNullOrWhiteSpace(r.Description)||string.IsNullOrWhiteSpace(r.RequestedBy))return Results.BadRequest(new{error="required_fields",message="ProjectId, title, description, and requestedBy are required."});try{var id=await s.CreateAsync(r,t);await events.AppendAsync(new CreateDomainEventRequest("DecisionRequested","Approval",id,r.ProjectId,null,r.RequestedBy,JsonSerializer.SerializeToElement(new{r.Title})),t);return Results.Created($"/api/approvals/{id}",await s.GetAsync(id,t));}catch(PostgresException ex)when(ex.SqlState==PostgresErrorCodes.ForeignKeyViolation){return Results.BadRequest(new{error="project_not_found",message=$"Project '{r.ProjectId}' does not exist."});}});g.MapPost("/{id}/actions",async(string id,ApprovalActionRequest r,ApprovalWorkflowService s,EventStoreService events,CancellationToken t)=>{if(string.IsNullOrWhiteSpace(r.Actor))return Results.BadRequest(new{error="actor_required",message="Actor is required."});try{if(!await s.ActAsync(id,r,t))return Results.NotFound();var item=await s.GetAsync(id,t);var type=r.Action.Equals("approve",StringComparison.OrdinalIgnoreCase)?"DecisionApproved":"DecisionUpdated";await events.AppendAsync(new CreateDomainEventRequest(type,"Approval",id,item!.ProjectId,null,r.Actor,JsonSerializer.SerializeToElement(new{r.Action,r.Comment})),t);return Results.Ok(item);}catch(ArgumentException ex){return Results.BadRequest(new{error="invalid_action",message=ex.Message});}});return app;}}
